function BrandItem({ name, imgKey }) {
  // Text-only style for brands without logos
  const textStyles = {
    "Electrolux": { fontFamily: "'DM Sans', sans-serif", fontWeight: 300, fontSize: 18, letterSpacing: "3px", textTransform: "uppercase" },
    "SMEG": { fontFamily: "'Playfair Display', serif", fontWeight: 700, fontSize: 22, letterSpacing: "4px", textTransform: "uppercase" },
    "GP Battery": { fontFamily: "'DM Sans', sans-serif", fontWeight: 800, fontSize: 17, letterSpacing: "0.5px", textTransform: "uppercase" },
    "Pharmex Healthcare": { fontFamily: "'DM Sans', sans-serif", fontWeight: 600, fontSize: 14, letterSpacing: "1px" },
    "KingsWood": { fontFamily: "'Playfair Display', serif", fontWeight: 600, fontSize: 19, letterSpacing: "1px" },
    "Nook & Cranny": { fontFamily: "'Playfair Display', serif", fontWeight: 400, fontSize: 18, letterSpacing: "1.5px", fontStyle: "italic" },
    "ErgoWorks": { fontFamily: "'DM Sans', sans-serif", fontWeight: 600, fontSize: 17, letterSpacing: "1px" },
    "Vanguard Interiors": { fontFamily: "'Playfair Display', serif", fontWeight: 700, fontSize: 15, letterSpacing: "2px", textTransform: "uppercase" },
    "Tashkila": { fontFamily: "'Playfair Display', serif", fontWeight: 600, fontSize: 20, letterSpacing: "2px" },
  };

  if (imgKey && LOGO_IMAGES[imgKey]) {
    return (
      <div style={{
        padding: "8px 28px", display: "flex", alignItems: "center",
        justifyContent: "center", minWidth: 140,
        opacity: 0.6, transition: "opacity 0.3s", cursor: "default",
      }}
        onMouseEnter={e => e.currentTarget.style.opacity = "1"}
        onMouseLeave={e => e.currentTarget.style.opacity = "0.6"}
      >
        <img src={LOGO_IMAGES[imgKey]} alt={name} style={{
          height: 36, width: "auto", objectFit: "contain",
          filter: "grayscale(100%)", transition: "filter 0.3s",
          mixBlendMode: "multiply",
        }}
          onMouseEnter={e => e.target.style.filter = "grayscale(0%)"}
          onMouseLeave={e => e.target.style.filter = "grayscale(100%)"}
        />
      </div>
    );
  }

  const s = textStyles[name] || {};
  return (
    <div style={{
      padding: "12px 28px", whiteSpace: "nowrap", color: COLORS.gray500,
      opacity: 0.55, transition: "opacity 0.3s", cursor: "default",
      display: "flex", alignItems: "center", justifyContent: "center",
      minWidth: 140, ...s,
    }}
      onMouseEnter={e => e.currentTarget.style.opacity = "0.9"}
      onMouseLeave={e => e.currentTarget.style.opacity = "0.55"}
    >
      {name}
    </div>
  );
}

